queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?movie a :Movie .
    ?movie p:title ?title .
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?tv_show a :Tv_Show .
    ?tv_show p:showName ?showname .
    ?tv_show p:genre ?genre_f .
    FILTER(STR(?genre_f) = "Fantasy")
    BIND(?showname AS ?o0)
  }
}

